 92→const CLIPBOARD_COLUMNS = new Set<string>([
 93→  'content',
 94→  'content_type',
 95→  'source_app',
 96→  'copied_at',
 97→  'pinned',
 98→]);
 99→
100→const SNIPPET_COLUMNS = new Set<string>([
101→  'name',
102→  'keyword',
103→  'content',
104→  'category',
105→  'tags',
106→  'created_at',
107→]);
