601→export const recentCommandDb = {
602→  async getAll(limit = 10): Promise<string[]> {
603→    if (isTauri) {
604→      const db = await getDb();
605→      const rows = await db.select<Pick<RecentCommandRow, 'command_id'>[]>(
606→        'SELECT command_id FROM recent_commands ORDER BY used_at DESC LIMIT $1',
607→        [limit],
608→      );
609→      return rows.map(r => r.command_id);
610→    }
611→    const stored = storageGet('recent-commands', isStringArray);
612→    return stored?.slice(0, limit) ?? [];
613→  },
614→  async add(commandId: string): Promise<void> {
615→    if (isTauri) {
616→      const db = await getDb();
617→      await db.execute('DELETE FROM recent_commands WHERE command_id = $1', [
618→        commandId,
619→      ]);
620→      await db.execute('INSERT INTO recent_commands (command_id) VALUES ($1)', [
621→        commandId,
622→      ]);
623→      await db.execute(
624→        `DELETE FROM recent_commands WHERE id NOT IN (
625→          SELECT id FROM recent_commands ORDER BY used_at DESC LIMIT 10
626→        )`,
627→      );
628→      return;
629→    }
630→    const all = await this.getAll();
631→    const next = [
632→      commandId,
633→      ...all.filter(id => id !== commandId),
634→    ].slice(0, 10);
635→    storageSet('recent-commands', next);
636→  },
637→  async clear(): Promise<void> {
638→    if (isTauri) {
639→      const db = await getDb();
640→      await db.execute('DELETE FROM recent_commands');
641→      return;
642→    }
643→    storageRemove('recent-commands');
644→  },
645→};
