647→export const settingsDb = {
648→  async get(key: string): Promise<string | null> {
649→    if (isTauri) {
650→      const db = await getDb();
651→      const rows = await db.select<SettingRow[]>(
652→        'SELECT value FROM settings WHERE key = $1',
653→        [key],
654→      );
655→      return rows[0]?.value ?? null;
656→    }
657→    const all = storageGet('settings-all', isSettingRowArray);
658→    return all?.find(r => r.key === key)?.value ?? null;
659→  },
660→  async set(key: string, value: string): Promise<void> {
661→    if (isTauri) {
662→      const db = await getDb();
663→      await db.execute(
664→        'INSERT INTO settings (key, value) VALUES ($1, $2) ON CONFLICT(key) DO UPDATE SET value = excluded.value',
665→        [
666→          key,
667→          value,
668→        ],
669→      );
670→      return;
671→    }
672→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
673→    const existing = all.findIndex(r => r.key === key);
674→    if (existing >= 0) {
675→      all[existing] = {
676→        key,
677→        value,
678→      };
679→    } else {
680→      all.push({
681→        key,
682→        value,
683→      });
684→    }
685→    storageSet('settings-all', all);
686→  },
687→  async delete(key: string): Promise<void> {
688→    if (isTauri) {
689→      const db = await getDb();
690→      await db.execute('DELETE FROM settings WHERE key = $1', [key]);
691→      return;
692→    }
693→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
694→    storageSet(
695→      'settings-all',
696→      all.filter(r => r.key !== key),
697→    );
698→  },
699→  async getAll(): Promise<SettingRow[]> {
700→    if (isTauri) {
701→      const db = await getDb();
702→      return db.select<SettingRow[]>('SELECT key, value FROM settings');
703→    }
704→    return storageGet('settings-all', isSettingRowArray) ?? [];
705→  },
706→};
