140→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
141→      result.push({
142→        title: 'Recently Used',
143→        emojis: recentEmojis,
144→      });
145→    }
146→
147→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
148→    for (const emoji of filtered) {
149→      const existing = grouped.get(emoji.category);
150→      if (existing) {
