261→
262→  useEffect(() => {
263→    function handleKeyDown(e: KeyboardEvent) {
264→      if (totalCount === 0) return;
265→      if (actionsOpen) return;
266→      if (e.metaKey || e.ctrlKey || e.altKey) return;
267→
268→      const isTextInput =
269→        e.target instanceof HTMLInputElement ||
270→        e.target instanceof HTMLTextAreaElement;
271→
272→      switch (e.key) {
273→        case 'ArrowRight': {
274→          if (isTextInput) return;
275→          e.preventDefault();
276→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
277→          break;
278→        }
279→        case 'ArrowLeft': {
280→          if (isTextInput) return;
281→          e.preventDefault();
282→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
283→          break;
284→        }
285→        case 'ArrowDown': {
286→          e.preventDefault();
287→          setActiveIndex(prev => {
288→            const sectionInfo = getSectionInfo(prev);
289→            if (!sectionInfo) return prev;
290→            const { sectionStart, sectionLength } = sectionInfo;
291→            const posInSection = prev - sectionStart;
292→            const row = Math.floor(posInSection / COLUMNS);
293→            const col = posInSection % COLUMNS;
294→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
295→
296→            if (row + 1 < sectionRows) {
297→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
298→              return nextIdx < sectionStart + sectionLength
299→                ? nextIdx
300→                : sectionStart + sectionLength - 1;
301→            }
302→
303→            const nextSectionStart = sectionStart + sectionLength;
304→            if (nextSectionStart < totalCount) {
305→              const nextInfo = getSectionInfo(nextSectionStart);
306→              if (!nextInfo) return prev;
307→              const targetIdx = nextSectionStart + col;
308→              return targetIdx < nextSectionStart + nextInfo.sectionLength
309→                ? targetIdx
310→                : nextSectionStart + nextInfo.sectionLength - 1;
311→            }
312→
313→            return prev;
314→          });
315→          break;
316→        }
317→        case 'ArrowUp': {
318→          e.preventDefault();
319→          setActiveIndex(prev => {
320→            const sectionInfo = getSectionInfo(prev);
321→            if (!sectionInfo) return prev;
322→            const { sectionStart } = sectionInfo;
323→            const posInSection = prev - sectionStart;
324→            const row = Math.floor(posInSection / COLUMNS);
325→            const col = posInSection % COLUMNS;
326→
327→            if (row > 0) {
328→              return sectionStart + (row - 1) * COLUMNS + col;
329→            }
330→
331→            if (sectionStart > 0) {
332→              const prevSectionEnd = sectionStart - 1;
333→              const prevInfo = getSectionInfo(prevSectionEnd);
334→              if (!prevInfo) return prev;
335→              const prevSectionRows = Math.ceil(
336→                prevInfo.sectionLength / COLUMNS,
337→              );
338→              const lastRowStart =
339→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
340→              const targetIdx = lastRowStart + col;
341→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
342→                ? targetIdx
343→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
344→            }
345→
346→            return prev;
347→          });
348→          break;
349→        }
350→        case 'Enter': {
351→          e.preventDefault();
352→          handleCopyEmoji();
353→          break;
354→        }
355→      }
356→    }
357→
358→    window.addEventListener('keydown', handleKeyDown);
359→    return () => window.removeEventListener('keydown', handleKeyDown);
360→  }, [
361→    totalCount,
362→    actionsOpen,
363→    handleCopyEmoji,
364→    sections,
365→  ]);
366→
367→  const sectionBoundaries = useMemo(() => {
368→    const boundaries: {
369→      start: number;
370→      length: number;
