428→                : 'Copied',
429→              onCopy: () => {
430→                if (selectedEmoji) addToRecent(selectedEmoji.char);
431→              },
432→            },
433→            showHUD,
434→          ),
435→        ],
436→      },
437→    ],
438→    [
439→      selectedEmoji,
440→      showHUD,
441→      addToRecent,
442→    ],
443→  );
444→
445→  const handleGridMouseOver = useCallback((
446→    e: React.MouseEvent<HTMLDivElement>,
447→  ) => {
448→    const target = (e.target as HTMLElement).closest<HTMLElement>(
449→      '[data-emoji-index]',
