451→    if (!target) return;
452→    const idx = Number(target.dataset.emojiIndex);
453→    if (!Number.isNaN(idx)) {
454→      setActiveIndex(idx);
455→    }
456→  }, []);
457→
458→  const activeDescendantId =
459→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
460→
461→  return (
462→    <>
463→      <SearchBar
