 43→interface GeneralSettings {
 44→  appearance: string;
 45→  windowPosition: string;
 46→  windowWidth: string;
 47→  showRecentApps: boolean;
 48→  showDock: boolean;
 49→  fontSize: string;
 50→}
 51→
 52→const SETTINGS_STORAGE_KEY = 'settings-general';
 53→const EXTENSIONS_STORAGE_KEY = 'settings-extensions';
 54→
 55→const DEFAULT_SETTINGS: GeneralSettings = {
 56→  appearance: 'dark',
 57→  windowPosition: 'top-third',
 58→  windowWidth: 'medium',
 59→  showRecentApps: true,
 60→  showDock: true,
 61→  fontSize: 'default',
 62→};
 63→
 64→function isGeneralSettings(value: unknown): value is GeneralSettings {
 65→  if (!isRecord(value)) return false;
 66→  return (
 67→    typeof value.appearance === 'string' &&
 68→    typeof value.windowWidth === 'string' &&
 69→    typeof value.showRecentApps === 'boolean' &&
 70→    typeof value.showDock === 'boolean' &&
 71→    typeof value.fontSize === 'string' &&
 72→    (value.windowPosition === undefined ||
 73→      typeof value.windowPosition === 'string')
 74→  );
 75→}
 76→
 77→function loadSettings(themePreference: string): GeneralSettings {
 78→  const stored = storageGet(SETTINGS_STORAGE_KEY, isGeneralSettings);
 79→  if (stored)
 80→    return {
 81→      ...stored,
 82→      appearance: themePreference,
 83→    };
 84→  return {
 85→    ...DEFAULT_SETTINGS,
 86→    appearance: themePreference,
 87→  };
 88→}
 89→
 90→function loadExtensions(): ExtensionEntry[] {
 91→  const states = storageGet(EXTENSIONS_STORAGE_KEY, isBooleanRecord);
 92→  return MOCK_EXTENSIONS.map(ext => ({
 93→    ...ext,
 94→    enabled: states ? (states[ext.id] ?? ext.enabled) : ext.enabled,
 95→  }));
 96→}
