779→            onClick: handleResetAll,
780→          },
781→        ],
782→      });
783→    }
784→
785→    return sections;
786→  }, [
787→    activeTab,
788→    handleExport,
789→    handleImport,
790→    handleClearCache,
791→    handleResetAll,
792→  ]);
793→
794→  return (
